import{_ as o,o as t,c as r,ag as a}from"./chunks/framework.BPmc_f4o.js";const g=JSON.parse('{"title":"Collections","description":"","frontmatter":{},"headers":[],"relativePath":"collections/collections.md","filePath":"collections/collections.md"}'),n={name:"collections/collections.md"};function s(i,e,l,p,d,c){return t(),r("div",null,[...e[0]||(e[0]=[a('<p><span style="display:inline-block;padding:1px 8px;border-radius:3px;background:#1565c0;color:#fff;font-size:11px;font-weight:600;">PRO</span></p><h1 id="collections" tabindex="-1">Collections <a class="header-anchor" href="#collections" aria-label="Permalink to &quot;Collections&quot;">​</a></h1><p>Collections extends REST API list endpoints with per-page enforcement and drag-and-drop ordering for posts and taxonomy terms. Like all Pro modules, Collections is scoped per application — each application can have its own per-page limits and its own sort order for each object type.</p><hr><h2 id="per-page-enforcement" tabindex="-1">Per Page Enforcement <a class="header-anchor" href="#per-page-enforcement" aria-label="Permalink to &quot;Per Page Enforcement&quot;">​</a></h2><p>Control how many items list endpoints return per request. Limits are configured per object type: set a value for posts, pages, any custom post type, attachments, or taxonomy terms individually. This replaces the WordPress default <code>per_page</code> parameter behaviour for the application.</p><hr><h2 id="drag-and-drop-sorting" tabindex="-1">Drag-and-Drop Sorting <a class="header-anchor" href="#drag-and-drop-sorting" aria-label="Permalink to &quot;Drag-and-Drop Sorting&quot;">​</a></h2><p>Drag-and-drop ordering is available for <strong>public post types</strong> and <strong>public taxonomies</strong> only.</p><p>Reordering is managed directly in the Collections panel — not in the WordPress post list admin screen.</p><h3 id="object-selection" tabindex="-1">Object selection <a class="header-anchor" href="#object-selection" aria-label="Permalink to &quot;Object selection&quot;">​</a></h3><p>A single selector lists all available public objects (post types and taxonomies). Select the object type you want to reorder. Once selected, the full list of entries for that object is loaded in the panel below and can be dragged to reorder.</p><p>If you need to reorder multiple object types, choose each one from the dropdown in turn. The order is saved per object type, per application.</p><h3 id="reorder-panel" tabindex="-1">Reorder panel <a class="header-anchor" href="#reorder-panel" aria-label="Permalink to &quot;Reorder panel&quot;">​</a></h3><p>Entries are displayed in a paginated list. Page size is configurable up to a maximum of 100 items per page. Drag rows to set their position. The saved order is always consistent across all pages — moving an entry on page 2 correctly offsets every entry across the full dataset.</p><p>Additional toolbar actions:</p><ul><li><strong>Invert order</strong> — reverses the current sequence of all entries in one click.</li><li><strong>Restore default order</strong> — resets all positions to the WordPress default order. A confirmation is required before the reset is applied.</li></ul><h3 id="order-enforcement" tabindex="-1">Order enforcement <a class="header-anchor" href="#order-enforcement" aria-label="Permalink to &quot;Order enforcement&quot;">​</a></h3><ul><li><strong>Apply Sort Order in REST Requests</strong> — when no <code>orderby</code> parameter is present in a REST list request, the saved order is applied automatically.</li></ul><hr><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><p><strong>How is sort order stored?</strong></p><p>Order is stored in the <code>menu_order</code> meta field on both posts and taxonomy terms.</p><ul><li>In the <strong>free tier</strong>, the value is stored as a single scalar keyed to <code>default_app</code>.</li><li>In <strong>Pro</strong>, each application stores its own order: <code>{ app_id: order }</code>.</li></ul><p>This means the same post or term can have a different position in each application&#39;s response.</p><p>On uninstallation, these meta values can optionally be removed. This behaviour is configurable in the global plugin settings panel.</p><p><strong>Does drag-and-drop work across pagination?</strong></p><p>Yes, the list sequence is maintained regardless of which page you are viewing.</p><p><strong>Which object types support ordering?</strong></p><p>Only public post types and public taxonomies. Private post types and non-public taxonomies are not available in the object selector.</p>',30)])])}const u=o(n,[["render",s]]);export{g as __pageData,u as default};
